+import com.github.javaparser.ast.ImportDeclaration;
+import com.github.javaparser.ast.Node;
+import com.github.javaparser.ast.visitor.ModifierVisitor;
+import com.github.javaparser.ast.visitor.Visitable;
+import com.github.javaparser.printer.lexicalpreservation.LexicalPreservingPrinter;
+import com.github.javaparser.utils.SourceRoot;
+
+import java.io.IOException;
+import java.nio.charset.StandardCharsets;
+import java.nio.file.Files;
+import java.nio.file.Path;
+import java.nio.file.Paths;
+
 public class Main {
+    private static final String OLD_RUNNER = "org.mockito.runners.MockitoJUnitRunner";
+    private static final String NEW_RUNNER = "org.mockito.junit.MockitoJUnitRunner";
+
     public static void main(String[] args) {
-
+        if (args.length == 0) {
+            throw new IllegalArgumentException("Expected a source root path");
+        }
+
+        Path sourceRootPath = Paths.get(args[0]);
+        try {
+            transformSourceTree(sourceRootPath);
+        } catch (IOException e) {
+            throw new RuntimeException(e);
+        }
+    }
+
+    private static void transformSourceTree(Path sourceRootPath) throws IOException {
+        ParserConfiguration configuration = new ParserConfiguration();
+        JavaParser parser = new JavaParser(configuration);
+        SourceRoot sourceRoot = new SourceRoot(sourceRootPath, configuration);
+
+        Files.walk(sourceRootPath)
+            .filter(path -> path.toString().endsWith(".java"))
+            .forEach(path -> {
+                try {
+                    CompilationUnit cu = parser.parse(path).getResult().orElseThrow();
+                    LexicalPreservingPrinter.setup(cu);
+                    cu.accept(new MockitoRunnerMigrationVisitor(), null);
+                    Files.writeString(path, LexicalPreservingPrinter.print(cu), StandardCharsets.UTF_8);
+                } catch (Exception e) {
+                    throw new RuntimeException("Failed to transform " + path, e);
+                }
+            });
+    }
+
+    private static final class MockitoRunnerMigrationVisitor extends ModifierVisitor<Void> {
+        @Override
+        public Visitable visit(ImportDeclaration n, Void arg) {
+            if (!n.isStatic() && n.getNameAsString().equals(OLD_RUNNER)) {
+                n.setName(NEW_RUNNER);
+            }
+            return super.visit(n, arg);
+        }
+
+        @Override
+        public Visitable visit(Node n, Void arg) {
+            if (n.toString().equals(OLD_RUNNER)) {
+                return super.visit(n, arg);
+            }
+            return super.visit(n, arg);
+        }
     }
 }
